const inputData = $input.item.json;
const message = inputData.message;
const output = { ...inputData };

if (!message) {
  output.error = true;
  output.errorMessage = '❌ No message found.';
  return [{ json: output }];
}

if (!message.photo || !Array.isArray(message.photo) || message.photo.length === 0) {
  output.error = true;
  output.errorMessage = '❌ No photo found. Please send an image of your product.';
  return [{ json: output }];
}

const photo = message.photo[message.photo.length - 1];
if (Math.min(photo.width, photo.height) < 480) {
  output.error = true;
  output.errorMessage = `❌ Image too small (${photo.width}x${photo.height}).\n\nMinimum: 480px — Recommended: 1024x1024 or larger`;
  return [{ json: output }];
}

output.chatId = message.chat?.id;
output.messageId = message.message_id;
output.caption = message.caption || '';
output.file_id = photo.file_id;
output.error = false;

return [{ json: output }];

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    if (!item.binary || !item.binary.data) {
      throw new Error('No binary data found');
    }

    let imageBuffer;
    let mimeType = 'image/jpeg';

    if (item.binary.data.data) {
      imageBuffer = Buffer.from(item.binary.data.data, 'base64');
      mimeType = item.binary.data.mimeType || mimeType;
    } else if (Buffer.isBuffer(item.binary.data)) {
      imageBuffer = item.binary.data;
      mimeType = item.binary.mimeType || mimeType;
    } else if (typeof item.binary.data === 'string') {
      imageBuffer = Buffer.from(item.binary.data, 'base64');
      mimeType = item.binary.mimeType || mimeType;
    } else {
      const binaryKeys = Object.keys(item.binary).filter(k =>
        !['mimeType', 'fileType', 'fileName', 'fileExtension'].includes(k)
      );
      if (binaryKeys.length > 0) {
        const binaryData = item.binary[binaryKeys[0]];
        imageBuffer = Buffer.isBuffer(binaryData) ? binaryData
          : binaryData.data ? Buffer.from(binaryData.data)
          : Buffer.from(binaryData);
        mimeType = item.binary.mimeType || mimeType;
      } else {
        throw new Error('Could not locate binary data');
      }
    }

    if (!imageBuffer || imageBuffer.length === 0) throw new Error('Empty image buffer');

    results.push({
      json: {
        ...item.json,
        imageBase64: imageBuffer.toString('base64'),
        imageMimeType: mimeType,
        imageSize: imageBuffer.length,
        conversionStatus: 'success'
      }
    });

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: true,
        conversionStatus: 'failed',
        conversionError: error.message
      }
    });
  }
}

return results;

const item = $input.item.json;

const basePrompt = `Create a professional 360-degree product showcase video. The camera smoothly orbits the product in a full 360-degree rotation, maintaining consistent framing. Use studio lighting with a clean white background. The product stays centered throughout. Smooth, cinematic movement — no jitter or cuts.`;

const userCaption = item.caption || '';
const finalPrompt = userCaption.trim().length > 0
  ? basePrompt + ` Product context: ${userCaption.trim()}`
  : basePrompt;

const apiPayload = {
  instances: [{
    prompt: finalPrompt,
    image: {
      bytesBase64Encoded: item.imageBase64,
      mimeType: item.imageMimeType
    }
  }],
  parameters: {
    aspectRatio: '16:9',
    sampleCount: 1,
    durationSeconds: 8,
    personGeneration: 'allow_all',
    addWatermark: true,
    includeRaiReason: true,
    generateAudio: true
  }
};

return {
  api_payload: JSON.stringify(apiPayload),
  chatId: item.chatId,
  messageId: item.messageId,
  caption: item.caption
};

const response = $input.item.json;

if (response.name) {
  return [{
    json: {
      operation_name: response.name,
      status: 'polling',
      poll_count: 0,
      chatId: response.chatId,
      messageId: response.messageId,
      caption: response.caption
    }
  }];
} else {
  return [{
    json: {
      ...response,
      error: 'No operation name returned from Vertex AI',
      status: 'failed'
    }
  }];
}

const item = $input.item.json;
const pollCount = (item.poll_count || 0) + 1;

if (pollCount > 40) {
  return {
    error: 'Video generation timeout',
    status: 'timeout',
    poll_count: pollCount,
    chatId: item.chatId,
    messageId: item.messageId
  };
}

return {
  operation_name: item.name || item.operation_name,
  poll_count: pollCount,
  status: 'polling',
  chatId: item.chatId,
  messageId: item.messageId,
  caption: item.caption
};

const item = $input.item.json;
const crypto = require('crypto');

const SERVICE_ACCOUNT_EMAIL = item.client_email;
const PRIVATE_KEY = item.private_key.replace(/\\n/g, '\n');
const PROJECT_ID = item.project_id;
const SCOPE = item.scope || 'https://www.googleapis.com/auth/cloud-platform';
const TOKEN_URI = 'https://oauth2.googleapis.com/token';
const now = Math.floor(Date.now() / 1000);

function base64url(input) {
  const buf = Buffer.isBuffer(input) ? input : Buffer.from(JSON.stringify(input));
  return buf.toString('base64').replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

try {
  const header = base64url({ alg: 'RS256', typ: 'JWT' });
  const claims = base64url({ iss: SERVICE_ACCOUNT_EMAIL, scope: SCOPE, aud: TOKEN_URI, iat: now, exp: now + 3600 });
  const signingInput = `${header}.${claims}`;
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(signingInput);
  sign.end();
  const signature = sign.sign(PRIVATE_KEY).toString('base64').replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');

  return [{ json: { ...item, jwt: `${signingInput}.${signature}`, project_id: PROJECT_ID, client_email: SERVICE_ACCOUNT_EMAIL, error: false } }];
} catch (err) {
  return [{ json: { ...item, error: true, errorMessage: `❌ JWT Build Failed: ${err.message}` } }];
}
